"use client";
import { FormEvent, useEffect, useState } from "react";
import VendorSidebar from "../sidebar";
import { createService, deleteService, getMyServices, updateService, uploadServiceImage } from "../../../../lib/vendor-api";
import { formatINR, VendorService } from "../../../../lib/vendors";

export default function VendorServicesPage(){const [services,setServices]=useState<VendorService[]>([]);const [name,setName]=useState("");const [description,setDescription]=useState("");const [price,setPrice]=useState("");const [editing,setEditing]=useState<number|null>(null);const [error,setError]=useState("");const [notice,setNotice]=useState("");const [loading,setLoading]=useState(true);const [saving,setSaving]=useState(false);const load=()=>{setLoading(true);getMyServices().then(d=>{setServices(d.services);setError("");}).catch(e=>setError(e.message||"Unable to load services.")).finally(()=>setLoading(false));};useEffect(load,[]);
async function submit(e:FormEvent){e.preventDefault();const amount=Number(price);if(!name.trim()||!Number.isFinite(amount)||amount<0){setError("Enter a service name and a valid non-negative price.");return;}setSaving(true);setError("");try{if(editing){const data=await updateService(editing,{name:name.trim(),description:description.trim(),priceFromMinor:Math.round(amount*100)});setServices(s=>s.map(x=>x.id===editing?data.service:x));setNotice("Service updated.");}else{const data=await createService({name:name.trim(),description:description.trim(),priceFromMinor:Math.round(amount*100)});setServices(s=>[data.service,...s]);setNotice("Service created.");}setName("");setDescription("");setPrice("");setEditing(null);}catch(e:any){setError(e.message||"Unable to save service.");}finally{setSaving(false);}}
function edit(s:VendorService){setEditing(s.id);setName(s.name);setDescription(s.description);setPrice(String(s.priceFromMinor/100));window.scrollTo({top:0,behavior:"smooth"});}async function remove(s:VendorService){if(!window.confirm(`Delete ${s.name}? Existing booking history may prevent deletion.`))return;try{await deleteService(s.id);setServices(x=>x.filter(i=>i.id!==s.id));setNotice("Service deleted.");}catch(e:any){setError(e.message||"Unable to delete service.");}}async function toggle(s:VendorService){try{const d=await updateService(s.id,{isActive:!s.isActive});setServices(x=>x.map(i=>i.id===s.id?d.service:i));setNotice(`Service is now ${d.service.isActive?"active":"hidden"}.`);}catch(e:any){setError(e.message||"Unable to update service.");}}async function upload(s:VendorService,file?:File){if(!file)return;setSaving(true);try{await uploadServiceImage(s.id,file,s.name);setNotice("Image uploaded. It will appear on the public profile after refresh.");}catch(e:any){setError(e.message||"Unable to upload image. Ensure Cloudinary is configured and use a JPEG, PNG, or WebP under 5MB.");}finally{setSaving(false);}}
return <div className="min-h-screen bg-[#fffdfc] md:flex"><VendorSidebar/><main className="flex-1 p-5 pt-20 md:p-10"><p className="text-sm font-bold uppercase tracking-[.16em] text-[#8B000F]">Vendor workspace</p><h1 className="mt-2 font-serif text-4xl font-bold text-[#5c1632]">Services</h1><p className="mt-2 text-slate-600">Create the services customers can request. Hidden services cannot be booked.</p>{notice&&<p role="status" className="mt-5 rounded-xl bg-emerald-50 p-4 text-emerald-800">{notice}</p>}{error&&<p role="alert" className="mt-5 rounded-xl bg-red-50 p-4 text-red-800">{error}</p>}<form onSubmit={submit} className="mt-7 grid gap-4 rounded-2xl border border-[#f0ded8] bg-white p-6 shadow-sm"><h2 className="text-xl font-bold text-[#6b1839]">{editing?"Edit service":"Add a service"}</h2><div><label htmlFor="service-name" className="mb-2 block text-sm font-semibold">Service name</label><input id="service-name" required value={name} onChange={e=>setName(e.target.value)} className="w-full rounded-xl border border-[#e7d4ce] px-4 py-3"/></div><div><label htmlFor="service-description" className="mb-2 block text-sm font-semibold">Description</label><textarea id="service-description" value={description} onChange={e=>setDescription(e.target.value)} rows={3} className="w-full rounded-xl border border-[#e7d4ce] px-4 py-3"/></div><div><label htmlFor="service-price" className="mb-2 block text-sm font-semibold">Starting price (INR)</label><input id="service-price" required value={price} onChange={e=>setPrice(e.target.value)} type="number" min="0" step="1" className="w-full rounded-xl border border-[#e7d4ce] px-4 py-3"/></div><div className="flex gap-3"><button disabled={saving} className="rounded-xl bg-[#8B000F] px-5 py-3 font-semibold text-white disabled:opacity-60">{saving?"Saving…":editing?"Save changes":"Add service"}</button>{editing&&<button type="button" onClick={()=>{setEditing(null);setName("");setDescription("");setPrice("");}} className="rounded-xl border border-[#8B000F] px-5 py-3 font-semibold text-[#8B000F]">Cancel</button>}</div></form><section className="mt-8 grid gap-4">{loading?Array.from({length:3}).map((_,i)=><div key={i} className="h-40 animate-pulse rounded-2xl bg-slate-100"/>):services.map(s=><article key={s.id} className="rounded-2xl border border-[#f0ded8] bg-white p-5 shadow-sm"><div className="flex flex-col justify-between gap-4 sm:flex-row"><div><div className="flex gap-2"><h2 className="text-lg font-bold text-[#6b1839]">{s.name}</h2><span className={`rounded-full px-2 py-1 text-xs font-semibold ${s.isActive?"bg-emerald-50 text-emerald-700":"bg-slate-100 text-slate-700"}`}>{s.isActive?"Active":"Hidden"}</span></div><p className="mt-2 text-slate-700">{s.description||"No description added."}</p><p className="mt-3 font-semibold">From {formatINR(s.priceFromMinor)}</p></div><div className="flex flex-wrap gap-2"><label className="cursor-pointer rounded-lg border border-[#8B000F] px-3 py-2 text-sm font-semibold text-[#8B000F]">Upload image<input className="sr-only" type="file" accept="image/jpeg,image/png,image/webp" disabled={saving} onChange={e=>upload(s,e.target.files?.[0])}/></label><button onClick={()=>edit(s)} className="rounded-lg border border-[#8B000F] px-3 py-2 text-sm font-semibold text-[#8B000F]">Edit</button><button onClick={()=>toggle(s)} className="rounded-lg border border-slate-300 px-3 py-2 text-sm font-semibold">{s.isActive?"Hide":"Make active"}</button><button onClick={()=>remove(s)} className="rounded-lg bg-red-700 px-3 py-2 text-sm font-semibold text-white">Delete</button></div></div></article>)}{!loading&&!services.length&&<div className="rounded-2xl border border-dashed border-[#d9bcb1] bg-white p-10 text-center"><h2 className="font-bold text-[#6b1839]">No services yet</h2><p className="mt-2 text-sm text-slate-600">Complete your profile, then add your first service.</p></div>}</section></main></div>}
